/// Safe parameter readers for uniform setters.
const double _maxSafeIntegerDouble = 9007199254740991.0;

bool _isSafeIntegerDouble(double value) {
  return value.isFinite && value.abs() <= _maxSafeIntegerDouble;
}

double readDouble(Map<String, Object> params, String key, double fallback) {
  final value = params[key];
  if (value is int) return value.toDouble();
  if (value is double && value.isFinite) return value;
  return fallback;
}

int readInt(Map<String, Object> params, String key, int fallback) {
  final value = params[key];
  if (value is int) return value;
  if (value is double && _isSafeIntegerDouble(value)) return value.round();
  return fallback;
}

import 'package:flutter_test/flutter_test.dart';

import 'package:flutter_fractals/core/modules/param_reader.dart';

void main() {
  group('readDouble', () {
    test('accepts finite int and double values', () {
      expect(readDouble({'power': 8}, 'power', 2.0), 8.0);
      expect(readDouble({'power': 3.5}, 'power', 2.0), 3.5);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readDouble(const {}, 'power', 2.0), 2.0);
      expect(readDouble({'power': '8'}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.nan}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.infinity}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.negativeInfinity}, 'power', 2.0), 2.0);
    });
  });

  group('readInt', () {
    test('accepts integer values and rounds finite doubles', () {
      expect(readInt({'iterations': 120}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.4}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.5}, 'iterations', 80), 121);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readInt(const {}, 'iterations', 80), 80);
      expect(readInt({'iterations': '120'}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.nan}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.infinity}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.negativeInfinity}, 'iterations', 80),
          80);
    });

    test('falls back for finite doubles outside integer range', () {
      expect(readInt({'iterations': 1e100}, 'iterations', 80), 80);
      expect(readInt({'iterations': -1e100}, 'iterations', 80), 80);
    });
  });
}

/// Uniform slot contracts shared by declarative module builders.
///
/// Keep these indices aligned with the matching fragment shaders. Centralizing
/// them makes shader/builder drift visible during review instead of burying the
/// contract as repeated magic numbers in setUniforms closures.
abstract final class EscapeTimeUniformSlots {
  static const int time = 0;
  static const int resolutionX = 1;
  static const int resolutionY = 2;
  static const int centerX = 3;
  static const int centerY = 4;
  static const int zoom = 5;
  static const int iterations = 6;
  static const int bailout = 7;
  static const int colorScheme = 8;
  static const int transparentBackground = 9;
  static const int extraStart = 10;
}

abstract final class Raymarched3DUniformSlots {
  static const int time = 0;
  static const int resolutionX = 1;
  static const int resolutionY = 2;
  static const int mouseX = 3;
  static const int mouseY = 4;
  static const int zoom = 5;
  static const int rotationX = 6;
  static const int rotationY = 7;
  static const int rotationZ = 8;
  static const int power = 9;
  static const int iterations = 10;
  static const int steps = 11;
  static const int bailout = 12;
  static const int colorScheme = 13;
  static const int fractalType = 14;
  static const int transparentBackground = 15;
}

import 'package:flutter_test/flutter_test.dart';

import 'package:flutter_fractals/core/modules/builders/uniform_layout.dart';

void main() {
  group('builder uniform layouts', () {
    test('escape-time slots expose the shader contract without gaps', () {
      expect(EscapeTimeUniformSlots.time, 0);
      expect(EscapeTimeUniformSlots.resolutionX, 1);
      expect(EscapeTimeUniformSlots.resolutionY, 2);
      expect(EscapeTimeUniformSlots.centerX, 3);
      expect(EscapeTimeUniformSlots.centerY, 4);
      expect(EscapeTimeUniformSlots.zoom, 5);
      expect(EscapeTimeUniformSlots.iterations, 6);
      expect(EscapeTimeUniformSlots.bailout, 7);
      expect(EscapeTimeUniformSlots.colorScheme, 8);
      expect(EscapeTimeUniformSlots.transparentBackground, 9);
      expect(EscapeTimeUniformSlots.extraStart, 10);
    });

    test('raymarched 3D slots expose the shader contract without gaps', () {
      expect(Raymarched3DUniformSlots.time, 0);
      expect(Raymarched3DUniformSlots.resolutionX, 1);
      expect(Raymarched3DUniformSlots.resolutionY, 2);
      expect(Raymarched3DUniformSlots.mouseX, 3);
      expect(Raymarched3DUniformSlots.mouseY, 4);
      expect(Raymarched3DUniformSlots.zoom, 5);
      expect(Raymarched3DUniformSlots.rotationX, 6);
      expect(Raymarched3DUniformSlots.rotationY, 7);
      expect(Raymarched3DUniformSlots.rotationZ, 8);
      expect(Raymarched3DUniformSlots.power, 9);
      expect(Raymarched3DUniformSlots.iterations, 10);
      expect(Raymarched3DUniformSlots.steps, 11);
      expect(Raymarched3DUniformSlots.bailout, 12);
      expect(Raymarched3DUniformSlots.colorScheme, 13);
      expect(Raymarched3DUniformSlots.fractalType, 14);
      expect(Raymarched3DUniformSlots.transparentBackground, 15);
    });
  });
}

import 'package:equatable/equatable.dart';
import 'package:vector_math/vector_math.dart';

/// Represents the complete rendering parameters for a fractal.
///
/// This class encapsulates all configurable options that affect how a fractal
/// is rendered, including mathematical parameters (power, iterations, bailout),
/// visual settings (color scheme, zoom), and spatial transformations (rotation).
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final params = FractalParams(
///   power: 8.0,
///   iterations: 100,
///   zoom: 2.0,
///   rotation: Vector3(0.5, 0.3, 0.0),
///   mousePos: Vector2.zero(),
/// );
/// ```
class FractalParams extends Equatable {
  /// The mathematical power used in fractal calculations.
  ///
  /// Higher values create more intricate patterns. For Mandelbulb fractals,
  /// values of 8 produce the classic shape, while lower or higher values
  /// create interesting variations.
  ///
  /// Typical range: 2.0 to 12.0
  final double power;

  /// The maximum number of iterations for escape-time calculations.
  ///
  /// Higher iteration counts reveal more detail but require more computation.
  /// Values between 50-200 are typical for interactive rendering.
  final int iterations;

  /// The escape radius threshold for fractal calculations.
  ///
  /// Points that exceed this distance from the origin are considered to have
  /// escaped. Lower values create sharper boundaries.
  ///
  /// Typical range: 1.0 to 4.0
  final double bailout;

  /// The current zoom/magnification level.
  ///
  /// Values greater than 1.0 zoom in, values less than 1.0 zoom out.
  /// Range is typically clamped to 0.1x - 10x.
  final double zoom;

  /// The 3D rotation angles for the fractal view.
  ///
  /// Used for 3D fractals (like Mandelbulb) to control camera orientation.
  /// Each component represents rotation around the X, Y, and Z axes respectively.
  final Vector3 rotation;

  /// The active color scheme index.
  ///
  /// Maps to [AppColorScheme] enum values:
  /// - 0: Fire
  /// - 1: Ocean
  /// - 2: Psychedelic
  /// - 3: Grayscale
  final int colorScheme;

  /// The current mouse/touch position in normalized coordinates.
  ///
  /// Used for interactive effects where the fractal responds to pointer position.
  final Vector2 mousePos;

  /// The type of fractal being rendered.
  ///
  /// Determines which algorithm is used for fractal generation.
  final FractalType fractalType;

  /// Creates a new [FractalParams] instance with the specified values.
  ///
  /// The [rotation] and [mousePos] vectors are required as they have no
  /// sensible universal default.
  const FractalParams({
    this.power = 8.0,
    this.iterations = 50,
    this.bailout = 2.0,
    this.zoom = 1.0,
    required this.rotation,
    this.colorScheme = 0,
    required this.mousePos,
    this.fractalType = FractalType.mandelbulb,
  });

  /// Creates a [FractalParams] with sensible default values.
  ///
  /// Useful for initialization when no specific parameters are needed.
  FractalParams.withDefaults()
      : power = 8.0,
        iterations = 50,
        bailout = 2.0,
        zoom = 1.0,
        rotation = Vector3(0.0, 0.0, 0.0),
        colorScheme = 0,
        mousePos = Vector2(0.0, 0.0),
        fractalType = FractalType.mandelbulb;

  /// Creates a copy of this [FractalParams] with the given fields replaced.
  ///
  /// All parameters are optional; unspecified parameters retain their
  /// original values.
  FractalParams copyWith({
    double? power,
    int? iterations,
    double? bailout,
    double? zoom,
    Vector3? rotation,
    int? colorScheme,
    Vector2? mousePos,
    FractalType? fractalType,
  }) {
    return FractalParams(
      power: power ?? this.power,
      iterations: iterations ?? this.iterations,
      bailout: bailout ?? this.bailout,
      zoom: zoom ?? this.zoom,
      rotation: rotation ?? this.rotation,
      colorScheme: colorScheme ?? this.colorScheme,
      mousePos: mousePos ?? this.mousePos,
      fractalType: fractalType ?? this.fractalType,
    );
  }

  @override
  List<Object?> get props => [
        power,
        iterations,
        bailout,
        zoom,
        rotation,
        colorScheme,
        mousePos,
        fractalType,
      ];
}

/// Available color schemes for fractal rendering.
///
/// Each scheme provides a distinct visual aesthetic for the fractal output.
enum AppColorScheme {
  /// Warm orange-red-yellow gradient, reminiscent of flames.
  fire,

  /// Cool blue-teal gradient, evoking underwater themes.
  ocean,

  /// Vibrant multi-color gradient with high saturation.
  psychedelic,

  /// Black-to-white gradient for a classic mathematical look.
  grayscale;
}

/// Types of fractals available for rendering.
///
/// Each type uses a different mathematical algorithm to generate
/// its characteristic patterns.
enum FractalType {
  /// 3D extension of the Mandelbrot set.
  ///
  /// Creates a bulbous, organic-looking 3D shape through
  /// spherical coordinate mapping.
  mandelbulb,

  /// Box-folding fractal with recursive transformations.
  ///
  /// Creates geometric, box-like structures with infinite detail.
  mandelbox,

  /// Complex-number iteration fractal.
  ///
  /// Uses a constant complex parameter to create varied 2D patterns.
  julia,

  /// Recursive tetrahedron subdivision.
  ///
  /// A 3D fractal created by iteratively removing tetrahedra
  /// from a larger tetrahedron.
  sierpinski;
}

import 'dart:async';

import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Parsed deep link data containing fractal configuration.
///
/// This class represents the configuration extracted from a deep link URL
/// like `fractalforge://view?type=mandelbrot&zoom=10&x=0.5`.
///
/// {@category Services}
class DeepLinkData {
  /// The fractal module ID (e.g., 'mandelbrot', 'julia', 'mandelbulb').
  final String type;

  /// Zoom level (magnification).
  final double? zoom;

  /// Pan X coordinate (2D fractals).
  final double? x;

  /// Pan Y coordinate (2D fractals).
  final double? y;

  /// Rotation X angle in radians (3D fractals).
  final double? rotX;

  /// Rotation Y angle in radians (3D fractals).
  final double? rotY;

  /// Rotation Z angle in radians (3D fractals).
  final double? rotZ;

  /// Number of iterations.
  final int? iterations;

  /// Bailout radius.
  final double? bailout;

  /// Color scheme index.
  final int? colorScheme;

  /// Power parameter (for fractals like Mandelbulb).
  final double? power;

  /// Julia set real constant (c.x).
  final double? juliaX;

  /// Julia set imaginary constant (c.y).
  final double? juliaY;

  const DeepLinkData({
    required this.type,
    this.zoom,
    this.x,
    this.y,
    this.rotX,
    this.rotY,
    this.rotZ,
    this.iterations,
    this.bailout,
    this.colorScheme,
    this.power,
    this.juliaX,
    this.juliaY,
  });

  /// Creates a [FractalViewState] from the parsed deep link data.
  FractalViewState toViewState() {
    return FractalViewState(
      pan: Vector2(x ?? 0.0, y ?? 0.0),
      zoom: zoom ?? 1.0,
      rotation: Vector3(rotX ?? 0.0, rotY ?? 0.0, rotZ ?? 0.0),
    );
  }

  /// Extracts fractal parameters from the deep link data.
  ///
  /// Returns a map of parameter IDs to values.
  Map<String, Object> toParams() {
    final params = <String, Object>{};

    if (iterations != null) params['iterations'] = iterations!;
    if (bailout != null) params['bailout'] = bailout!;
    if (colorScheme != null) params['colorScheme'] = colorScheme!;
    if (power != null) params['power'] = power!;
    if (juliaX != null) params['juliaX'] = juliaX!;
    if (juliaY != null) params['juliaY'] = juliaY!;

    return params;
  }

  @override
  String toString() {
    return 'DeepLinkData(type: $type, zoom: $zoom, x: $x, y: $y, '
        'rotX: $rotX, rotY: $rotY, rotZ: $rotZ, iterations: $iterations, '
        'bailout: $bailout, colorScheme: $colorScheme, power: $power, '
        'juliaX: $juliaX, juliaY: $juliaY)';
  }
}

/// Service for handling deep links with the `fractalforge://` scheme.
///
/// Supports URLs like:
/// - `fractalforge://view?type=mandelbrot&zoom=10&x=-0.5&y=0.1`
/// - `fractalforge://view?type=julia&juliaX=-0.7&juliaY=0.27&colorScheme=2`
/// - `fractalforge://view?type=mandelbulb&rotX=0.5&rotY=0.3&power=8`
///
/// {@category Services}
class _DeepLinkRoute {
  static const allowedWebHosts = {'fractalforge.app', 'www.fractalforge.app'};

  final bool isAccepted;

  const _DeepLinkRoute._(this.isAccepted);

  factory _DeepLinkRoute.fromUri(Uri uri) {
    if (uri.scheme == DeepLinkService.scheme) {
      return _DeepLinkRoute._(_isCustomViewRoute(uri));
    }

    if (uri.scheme == 'https') {
      return _DeepLinkRoute._(
        allowedWebHosts.contains(uri.host) && _isWebViewRoute(uri),
      );
    }

    return const _DeepLinkRoute._(false);
  }

  static bool _isCustomViewRoute(Uri uri) {
    return uri.host == DeepLinkService.host ||
        uri.path == '/${DeepLinkService.host}' ||
        uri.path == DeepLinkService.host;
  }

  static bool _isWebViewRoute(Uri uri) {
    return uri.path == '/${DeepLinkService.host}';
  }
}

class _DeepLinkModuleId {
  static final RegExp _safePattern = RegExp(r'^[a-z0-9_]+$');

  const _DeepLinkModuleId._();

  static bool isSafe(String moduleId) => _safePattern.hasMatch(moduleId);

  static String requireSafeForBuild(String moduleId) {
    if (!isSafe(moduleId)) {
      throw ArgumentError.value(
        moduleId,
        'moduleId',
        'Deep-link module IDs must match ${_safePattern.pattern}',
      );
    }
    return moduleId;
  }
}

class _DeepLinkQuery {
  static final recognizedNames = {
    'type',
    for (final param in DeepLinkService._allQueryParams) param.name,
  };

  final Map<String, String> _params;

  const _DeepLinkQuery._(this._params);

  factory _DeepLinkQuery.fromUri(Uri uri) {
    final duplicatedRecognizedKeys = uri.queryParametersAll.entries.where(
      (entry) => recognizedNames.contains(entry.key) && entry.value.length > 1,
    );
    if (duplicatedRecognizedKeys.isNotEmpty) {
      throw FormatException(
        'Duplicate deep-link query parameter: '
        '${duplicatedRecognizedKeys.first.key}',
      );
    }

    return _DeepLinkQuery._(uri.queryParameters);
  }

  String? operator [](String name) => _params[name];
}

abstract interface class _DeepLinkQueryParamContract {
  String get name;
}

class _BoundedDoubleQueryParam implements _DeepLinkQueryParamContract {
  @override
  final String name;
  final double min;
  final double max;

  const _BoundedDoubleQueryParam(this.name, this.min, this.max);

  double? parse(_DeepLinkQuery query) {
    return DeepLinkService._parseBoundedDouble(query[name], min, max, name);
  }

  String? format(Object? value, {bool preservePrecision = false}) {
    final parsed = DeepLinkService._tryFiniteDouble(value);
    if (parsed == null || !_contains(parsed)) {
      return null;
    }
    return DeepLinkService._formatDouble(
      parsed,
      preservePrecision: preservePrecision,
    );
  }

  bool _contains(double value) => value >= min && value <= max;
}

class _BoundedIntQueryParam implements _DeepLinkQueryParamContract {
  @override
  final String name;
  final int min;
  final int max;

  const _BoundedIntQueryParam(this.name, this.min, this.max);

  int? parse(_DeepLinkQuery query) {
    return DeepLinkService._parseBoundedInt(query[name], min, max, name);
  }

  String? format(Object? value) {
    final parsed = DeepLinkService._tryInt(value);
    if (parsed == null || !_contains(parsed)) {
      return null;
    }
    return parsed.toString();
  }

  bool _contains(int value) => value >= min && value <= max;
}

class DeepLinkService {
  static const String scheme = 'fractalforge';
  static const String host = 'view';

  static const _zoomParam = _BoundedDoubleQueryParam('zoom', 0.001, 1e15);
  static const _xParam = _BoundedDoubleQueryParam('x', -1e10, 1e10);
  static const _yParam = _BoundedDoubleQueryParam('y', -1e10, 1e10);
  static const _rotXParam = _BoundedDoubleQueryParam('rotX', -1e10, 1e10);
  static const _rotYParam = _BoundedDoubleQueryParam('rotY', -1e10, 1e10);
  static const _rotZParam = _BoundedDoubleQueryParam('rotZ', -1e10, 1e10);
  static const _iterationsParam = _BoundedIntQueryParam('iterations', 1, 10000);
  static const _bailoutParam = _BoundedDoubleQueryParam('bailout', 1.0, 1e10);
  static const _colorSchemeParam =
      _BoundedIntQueryParam('colorScheme', 0, 9999);
  static const _powerParam = _BoundedDoubleQueryParam('power', 1, 20);
  static const _juliaXParam = _BoundedDoubleQueryParam('juliaX', -1e10, 1e10);
  static const _juliaYParam = _BoundedDoubleQueryParam('juliaY', -1e10, 1e10);

  static const List<_DeepLinkQueryParamContract> _allQueryParams = [
    _zoomParam,
    _xParam,
    _yParam,
    _rotXParam,
    _rotYParam,
    _rotZParam,
    _iterationsParam,
    _bailoutParam,
    _colorSchemeParam,
    _powerParam,
    _juliaXParam,
    _juliaYParam,
  ];

  // Method channel for receiving deep links from native code
  static const MethodChannel _channel =
      MethodChannel('com.fractalforge/deeplink');

  final StreamController<DeepLinkData> _linkController =
      StreamController<DeepLinkData>.broadcast();

  /// Stream of parsed deep link data.
  Stream<DeepLinkData> get linkStream => _linkController.stream;

  DeepLinkData? _initialLink;

  /// The initial deep link that launched the app (if any).
  DeepLinkData? get initialLink => _initialLink;

  /// Initializes the deep link service.
  ///
  /// Sets up listeners for incoming deep links from the platform.
  Future<void> initialize() async {
    // TEMPORARY SAFETY SWITCH (2026-02): deep link channel init causes a black screen
    // on some Samsung S24 devices during startup.
    // User confirmed deep links are not needed for the immediate release.
    // We leave parsing + stream support intact for later re-enable.
    const bool kEnableDeepLinks =
        bool.fromEnvironment('ENABLE_DEEP_LINKS', defaultValue: false);
    if (!kEnableDeepLinks) {
      return;
    }

    // Set up method channel handler for incoming links
    _channel.setMethodCallHandler(_handleMethodCall);

    // Try to get the initial link that launched the app
    try {
      final Object? initialUri = await _channel.invokeMethod('getInitialLink');
      final data = parseIncomingLink(initialUri);
      if (data != null) {
        _initialLink = data;
      }
    } on PlatformException {
      // Platform doesn't support deep links or no initial link
    }
  }

  Future<dynamic> _handleMethodCall(MethodCall call) async {
    if (call.method == 'onDeepLink') {
      final data = parseIncomingLink(call.arguments);
      if (data != null) {
        _linkController.add(data);
      }
    }
  }

  /// Parses a platform-provided deep-link payload into [DeepLinkData].
  ///
  /// Native channels are expected to send URI strings, but malformed payloads
  /// are ignored instead of crashing the method-channel handler.
  static DeepLinkData? parseIncomingLink(
    Object? link, {
    List<String>? validFractalTypes,
  }) {
    if (link is! String || link.isEmpty) {
      return null;
    }

    try {
      return parseUri(
        Uri.parse(link),
        validFractalTypes: validFractalTypes,
      );
    } catch (e) {
      // Malformed URI, ignore.
      if (kDebugMode) debugPrint('Failed to parse deep link URI: $e');
      return null;
    }
  }

  /// Parses a URI into [DeepLinkData].
  ///
  /// Returns null if the URI is not a valid fractalforge deep link or
  /// if the fractal type is not recognized.
  static DeepLinkData? parseUri(Uri uri, {List<String>? validFractalTypes}) {
    final route = _DeepLinkRoute.fromUri(uri);
    if (!route.isAccepted) {
      return null;
    }

    final _DeepLinkQuery query;
    try {
      query = _DeepLinkQuery.fromUri(uri);
    } on FormatException catch (e) {
      if (kDebugMode) debugPrint('DeepLink: ${e.message} — rejecting link');
      return null;
    }

    final type = query['type'];

    if (type == null || type.isEmpty) {
      return null;
    }

    // Reject type strings with unsafe characters (defense-in-depth).
    if (!_DeepLinkModuleId.isSafe(type)) {
      return null;
    }

    // Validate fractal type if validation list provided
    if (validFractalTypes != null && !validFractalTypes.contains(type)) {
      return null;
    }

    return DeepLinkData(
      type: type,
      zoom: _zoomParam.parse(query),
      x: _xParam.parse(query),
      y: _yParam.parse(query),
      rotX: _rotXParam.parse(query),
      rotY: _rotYParam.parse(query),
      rotZ: _rotZParam.parse(query),
      iterations: _iterationsParam.parse(query),
      bailout: _bailoutParam.parse(query),
      colorScheme: _colorSchemeParam.parse(query),
      power: _powerParam.parse(query),
      juliaX: _juliaXParam.parse(query),
      juliaY: _juliaYParam.parse(query),
    );
  }

  /// Builds a shareable deep link URL from the current fractal state.
  ///
  /// The [moduleId] specifies the fractal type, [params] contains the
  /// fractal parameters, and [view] contains the camera/view state.
  static Uri buildUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final queryParams = <String, String>{
      'type': _DeepLinkModuleId.requireSafeForBuild(moduleId),
    };

    // Add view state. Use the same bounded contracts as parsing so generated
    // links do not round-trip through clamped or invalid camera values.
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _zoomParam,
      view.zoom,
      defaultValue: 1.0,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _xParam,
      view.pan.x,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _yParam,
      view.pan.y,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
        queryParams, _rotXParam, view.rotation.x);
    _addNonDefaultBoundedDoubleQueryParam(
        queryParams, _rotYParam, view.rotation.y);
    _addNonDefaultBoundedDoubleQueryParam(
        queryParams, _rotZParam, view.rotation.z);

    // Add fractal parameters. Unsupported values are omitted rather than
    // converted to sentinel values that parse back as valid-but-wrong params.
    _addBoundedIntQueryParam(
        queryParams, _iterationsParam, params['iterations']);
    _addBoundedDoubleQueryParam(queryParams, _bailoutParam, params['bailout']);
    _addBoundedIntQueryParam(
      queryParams,
      _colorSchemeParam,
      params['colorScheme'],
    );
    _addBoundedDoubleQueryParam(queryParams, _powerParam, params['power']);
    _addBoundedDoubleQueryParam(
      queryParams,
      _juliaXParam,
      params['juliaX'],
      preservePrecision: true,
    );
    _addBoundedDoubleQueryParam(
      queryParams,
      _juliaYParam,
      params['juliaY'],
      preservePrecision: true,
    );

    return Uri(
      scheme: scheme,
      host: host,
      queryParameters: queryParams,
    );
  }

  /// Builds a web-compatible URL for sharing.
  ///
  /// Uses a hypothetical web domain for universal link support.
  static Uri buildWebUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final customUri = buildUri(moduleId: moduleId, params: params, view: view);
    return Uri(
      scheme: 'https',
      host: 'fractalforge.app',
      path: '/view',
      queryParameters: customUri.queryParameters,
    );
  }

  static double? _parseBoundedDouble(
      String? v, double min, double max, String paramName) {
    if (v == null) return null;
    final d = double.tryParse(v);
    if (d == null || d.isNaN || d.isInfinite) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = d.clamp(min, max);
    if (clamped != d) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $d out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static int? _parseBoundedInt(String? v, int min, int max, String paramName) {
    if (v == null) return null;
    final i = int.tryParse(v);
    if (i == null) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = i.clamp(min, max);
    if (clamped != i) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $i out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static String _formatDouble(
    double value, {
    bool preservePrecision = false,
  }) {
    // Keep integer-looking values compact without truncating significant deep-zoom
    // view coordinates that need more than six decimal places to round-trip.
    if (value == value.truncateToDouble()) {
      return value.toInt().toString();
    }

    final compactFixed =
        value.toStringAsFixed(6).replaceAll(RegExp(r'\.?0+$'), '');
    if (!preservePrecision || double.tryParse(compactFixed) == value) {
      return compactFixed;
    }

    return value.toString();
  }

  static void _addBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    bool preservePrecision = false,
  }) {
    final formatted = param.format(
      value,
      preservePrecision: preservePrecision,
    );
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static void _addNonDefaultBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    double defaultValue = 0.0,
    bool preservePrecision = false,
  }) {
    final parsed = _tryFiniteDouble(value);
    if (parsed == null || parsed == defaultValue) return;
    _addBoundedDoubleQueryParam(
      queryParams,
      param,
      parsed,
      preservePrecision: preservePrecision,
    );
  }

  static void _addBoundedIntQueryParam(
    Map<String, String> queryParams,
    _BoundedIntQueryParam param,
    Object? value,
  ) {
    final formatted = param.format(value);
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static double? _tryFiniteDouble(Object? value) {
    final parsed = switch (value) {
      double v => v,
      int v => v.toDouble(),
      String v => double.tryParse(v),
      _ => null,
    };
    if (parsed == null || parsed.isNaN || parsed.isInfinite) {
      return null;
    }
    return parsed;
  }

  static int? _tryInt(Object? value) {
    return switch (value) {
      int v => v,
      String v => int.tryParse(v),
      _ => null,
    };
  }

  /// Disposes of the service and closes the stream.
  void dispose() {
    _linkController.close();
  }
}

